import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Usage (New)","description":"","frontmatter":{"title":"Usage (New)","slug":"billing-usage-new"},"headers":[],"relativePath":"account-hub/billing-usage-new.md","filePath":"account-hub/billing-usage-new.md"}'),n={name:"account-hub/billing-usage-new.md"};function i(s,e,l,u,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://branchdocs.app.link/e/home-page-to-dashboard" target="_blank" rel="noreferrer">Branch</a> gives you insight into metrics that impact your Branch invoice.</p><p>You can use this information to measure utilization for the current month, so that you do not go over your allowed limits. It allows you to analyze trends from month to month.</p><p>Depending on your plan, Branch will reflect either your app’s <strong>monthly active users (MAU)</strong> count, or it will show <strong>volume credit</strong> usage.</p><h3 id="monthly-active-users" tabindex="-1">Monthly active users <a class="header-anchor" href="#monthly-active-users" aria-label="Permalink to &quot;Monthly active users&quot;">​</a></h3><p>MAU is the number of unique individuals that interact with your web or app properties on a monthly basis.</p><p>Branch calculates your MAU count, which can be useful for determining the effectiveness of your marketing campaigns for your app.</p><h3 id="volume-credits" tabindex="-1">Volume credits <a class="header-anchor" href="#volume-credits" aria-label="Permalink to &quot;Volume credits&quot;">​</a></h3><p>Volume credits correspond to the number of end-user actions tracked, attributed, and reported on in Branch.</p><h2 id="track-usage" tabindex="-1">Track usage <a class="header-anchor" href="#track-usage" aria-label="Permalink to &quot;Track usage&quot;">​</a></h2><p>How you view your app’s usage metrics will depend on whether your account uses Branch’s new or legacy billing experience.</p><p>On the <a href="https://branchdocs.app.link/billing-new-to-billing-settings" target="_blank" rel="noreferrer">Billing tab</a>, you will find a module called Volume Credit Usage. This module shows you the number of volume credits your app has used this month, out of the total number of volume credits you have purchased. This bar resets monthly.</p><p>From this same module, you can click <strong>Manage Plan</strong> to adjust your Branch package.</p>',13)])])}const m=a(n,[["render",i]]);export{p as __pageData,m as default};
